/* OptiCrop — Premium Dark-Green Theme */
:root {
  --primary: #1a472a;
  --primary-light: #2d6a4f;
  --primary-dark: #0d2818;
  --accent: #74c69d;
  --accent-light: #95d5b2;
  --accent-dark: #40916c;
  --gold: #f4a261;
  --gold-light: #f7c59f;
  --gold-dark: #e76f51;
  --bg-dark: #0d1b12;
  --bg-card: rgba(26, 71, 42, 0.35);
  --bg-glass: rgba(13, 27, 18, 0.75);
  --text-primary: #e8f5e9;
  --text-secondary: #a8c5b0;
  --text-muted: #6b8f7a;
  --border-glass: rgba(116, 198, 157, 0.18);
  --shadow-glow: 0 0 40px rgba(116, 198, 157, 0.12);
  --shadow-card: 0 8px 32px rgba(0, 0, 0, 0.35);
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --radius-xl: 28px;
  --font-display: 'Playfair Display', Georgia, serif;
  --font-body: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

*, *::before, *::after {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  background: var(--bg-dark);
  background-image:
    radial-gradient(ellipse at 20% 0%, rgba(26, 71, 42, 0.45) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 100%, rgba(116, 198, 157, 0.08) 0%, transparent 50%),
    linear-gradient(180deg, var(--bg-dark) 0%, #0a1410 100%);
  color: var(--text-primary);
  min-height: 100vh;
  line-height: 1.6;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-display);
  font-weight: 600;
  color: var(--text-primary);
}

a {
  color: var(--accent);
  text-decoration: none;
  transition: color var(--transition);
}

a:hover {
  color: var(--accent-light);
}

.text-accent { color: var(--accent) !important; }
.text-gold { color: var(--gold) !important; }
.text-muted-custom { color: var(--text-muted) !important; }
.fw-600 { font-weight: 600; }

/* Navbar */
.opticrop-nav {
  background: var(--bg-glass) !important;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid var(--border-glass);
  padding: 0.75rem 0;
  transition: background var(--transition);
}

.opticrop-nav.scrolled {
  background: rgba(13, 27, 18, 0.95) !important;
  box-shadow: var(--shadow-card);
}

.navbar-brand .brand-text {
  font-family: var(--font-display);
  font-size: 1.35rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.02em;
}

.brand-badge {
  font-size: 0.65rem;
  font-weight: 700;
  background: linear-gradient(135deg, var(--gold), var(--gold-dark));
  color: var(--bg-dark);
  padding: 0.15rem 0.45rem;
  border-radius: 6px;
  letter-spacing: 0.08em;
  vertical-align: middle;
}

.brand-icon-img {
  filter: drop-shadow(0 0 8px rgba(116, 198, 157, 0.4));
}

.navbar-nav .nav-link {
  color: var(--text-secondary) !important;
  font-weight: 500;
  font-size: 0.9rem;
  padding: 0.5rem 1rem !important;
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.navbar-nav .nav-link:hover,
.navbar-nav .nav-link.active {
  color: var(--accent) !important;
  background: rgba(116, 198, 157, 0.08);
}

/* Glass Cards */
.glass-card {
  background: var(--bg-glass);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--border-glass);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-card);
  transition: transform var(--transition), box-shadow var(--transition), border-color var(--transition);
}

.glass-card:hover {
  border-color: rgba(116, 198, 157, 0.35);
  box-shadow: var(--shadow-glow), var(--shadow-card);
}

.glass-card-static:hover {
  transform: none;
  box-shadow: var(--shadow-card);
}

/* Hero Section */
.hero-section {
  position: relative;
  min-height: 88vh;
  display: flex;
  align-items: center;
  padding: 6rem 0 4rem;
  overflow: hidden;
}

.hero-section::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at 70% 30%, rgba(116, 198, 157, 0.12) 0%, transparent 45%),
    radial-gradient(circle at 30% 70%, rgba(244, 162, 97, 0.06) 0%, transparent 40%);
  pointer-events: none;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  background: rgba(116, 198, 157, 0.12);
  border: 1px solid var(--border-glass);
  color: var(--accent);
  padding: 0.4rem 1rem;
  border-radius: 50px;
  font-size: 0.85rem;
  font-weight: 500;
  margin-bottom: 1.5rem;
}

.hero-title {
  font-size: clamp(2.5rem, 5vw, 4rem);
  line-height: 1.15;
  margin-bottom: 1.25rem;
  background: linear-gradient(135deg, var(--text-primary) 0%, var(--accent-light) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-subtitle {
  font-size: 1.15rem;
  color: var(--text-secondary);
  max-width: 540px;
  margin-bottom: 2rem;
}

.hero-visual {
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
}

.hero-orb {
  width: 320px;
  height: 320px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(116, 198, 157, 0.25) 0%, transparent 70%);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 8rem;
  animation: float 6s ease-in-out infinite;
}

.hero-stats-row {
  display: flex;
  gap: 2rem;
  margin-top: 2.5rem;
  flex-wrap: wrap;
}

.hero-stat {
  text-align: center;
}

.hero-stat-value {
  font-family: var(--font-display);
  font-size: 2rem;
  font-weight: 700;
  color: var(--gold);
}

.hero-stat-label {
  font-size: 0.8rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* Section Layouts */
.section-padding {
  padding: 5rem 0;
}

.section-label {
  display: inline-block;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--accent);
  margin-bottom: 0.75rem;
}

.section-title {
  font-size: clamp(1.75rem, 3vw, 2.5rem);
  margin-bottom: 1rem;
}

.section-desc {
  color: var(--text-secondary);
  max-width: 600px;
  margin-bottom: 3rem;
}

/* Feature Cards */
.feature-card {
  padding: 2rem;
  height: 100%;
}

.feature-icon {
  width: 56px;
  height: 56px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, var(--primary), var(--primary-light));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  margin-bottom: 1.25rem;
  border: 1px solid var(--border-glass);
}

.feature-card h4 {
  font-size: 1.15rem;
  margin-bottom: 0.75rem;
}

.feature-card p {
  color: var(--text-secondary);
  font-size: 0.9rem;
  margin-bottom: 0;
}

/* Stats Cards */
.stat-card {
  padding: 1.75rem;
  text-align: center;
}

.stat-card .stat-icon {
  font-size: 2rem;
  margin-bottom: 0.75rem;
}

.stat-card .stat-value {
  font-family: var(--font-display);
  font-size: 2.25rem;
  font-weight: 700;
  color: var(--accent);
}

.stat-card .stat-label {
  color: var(--text-muted);
  font-size: 0.85rem;
  margin-top: 0.25rem;
}

/* Architecture Diagram */
.architecture-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
  gap: 1rem;
  align-items: center;
}

.arch-node {
  padding: 1.25rem;
  text-align: center;
  border-radius: var(--radius-md);
  background: rgba(26, 71, 42, 0.4);
  border: 1px solid var(--border-glass);
}

.arch-node .arch-icon {
  font-size: 1.75rem;
  margin-bottom: 0.5rem;
}

.arch-node .arch-label {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text-secondary);
}

.arch-arrow {
  text-align: center;
  color: var(--accent);
  font-size: 1.25rem;
}

/* Forms */
.form-section {
  padding: 3rem 0 5rem;
}

.form-card {
  padding: 2.5rem;
  max-width: 800px;
  margin: 0 auto;
}

.form-label {
  color: var(--text-secondary);
  font-weight: 500;
  font-size: 0.875rem;
  margin-bottom: 0.4rem;
}

.form-control,
.form-select {
  background: rgba(13, 27, 18, 0.6) !important;
  border: 1px solid var(--border-glass) !important;
  color: var(--text-primary) !important;
  border-radius: var(--radius-sm) !important;
  padding: 0.65rem 1rem !important;
  transition: border-color var(--transition), box-shadow var(--transition);
}

.form-control:focus,
.form-select:focus {
  border-color: var(--accent) !important;
  box-shadow: 0 0 0 3px rgba(116, 198, 157, 0.15) !important;
  background: rgba(13, 27, 18, 0.8) !important;
}

.form-control::placeholder {
  color: var(--text-muted) !important;
}

.form-select option {
  background: var(--bg-dark);
  color: var(--text-primary);
}

.input-group-text {
  background: rgba(26, 71, 42, 0.5) !important;
  border: 1px solid var(--border-glass) !important;
  color: var(--accent) !important;
}

.form-hint {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.25rem;
}

/* Buttons */
.btn-primary-custom {
  background: linear-gradient(135deg, var(--primary-light), var(--accent-dark));
  border: none;
  color: var(--text-primary);
  font-weight: 600;
  padding: 0.7rem 1.75rem;
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.btn-primary-custom:hover {
  background: linear-gradient(135deg, var(--accent-dark), var(--accent));
  color: var(--bg-dark);
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(116, 198, 157, 0.25);
}

.btn-gold {
  background: linear-gradient(135deg, var(--gold), var(--gold-dark));
  border: none;
  color: var(--bg-dark);
  font-weight: 600;
  padding: 0.7rem 1.75rem;
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.btn-gold:hover {
  background: linear-gradient(135deg, var(--gold-light), var(--gold));
  color: var(--bg-dark);
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(244, 162, 97, 0.3);
}

.btn-outline-accent {
  background: transparent;
  border: 1px solid var(--accent);
  color: var(--accent);
  font-weight: 600;
  padding: 0.7rem 1.75rem;
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.btn-outline-accent:hover {
  background: rgba(116, 198, 157, 0.12);
  color: var(--accent-light);
  border-color: var(--accent-light);
}

.btn-warning {
  background: linear-gradient(135deg, var(--gold), var(--gold-dark)) !important;
  border: none !important;
  color: var(--bg-dark) !important;
  font-weight: 600;
}

.btn-outline-warning {
  border-color: var(--gold) !important;
  color: var(--gold) !important;
}

.btn-outline-warning:hover {
  background: rgba(244, 162, 97, 0.12) !important;
  color: var(--gold-light) !important;
}

/* Algorithm Selector */
.algorithm-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
  gap: 0.75rem;
}

.algo-option {
  position: relative;
}

.algo-option input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.algo-option label {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  padding: 1rem 0.75rem;
  border: 1px solid var(--border-glass);
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: all var(--transition);
  text-align: center;
  font-size: 0.8rem;
  color: var(--text-secondary);
  background: rgba(13, 27, 18, 0.4);
}

.algo-option label .algo-icon {
  font-size: 1.5rem;
}

.algo-option input:checked + label {
  border-color: var(--accent);
  background: rgba(116, 198, 157, 0.12);
  color: var(--accent);
  box-shadow: 0 0 20px rgba(116, 198, 157, 0.15);
}

.algo-option label:hover {
  border-color: rgba(116, 198, 157, 0.4);
}

/* Sample Values */
.sample-presets {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-bottom: 1.5rem;
}

.sample-btn {
  background: rgba(26, 71, 42, 0.5);
  border: 1px solid var(--border-glass);
  color: var(--text-secondary);
  padding: 0.35rem 0.85rem;
  border-radius: 50px;
  font-size: 0.78rem;
  cursor: pointer;
  transition: all var(--transition);
}

.sample-btn:hover {
  border-color: var(--accent);
  color: var(--accent);
  background: rgba(116, 198, 157, 0.1);
}

/* Result Page */
.result-hero {
  text-align: center;
  padding: 3rem 2rem;
}

.result-crop-emoji {
  font-size: 5rem;
  line-height: 1;
  margin-bottom: 1rem;
  filter: drop-shadow(0 0 20px rgba(116, 198, 157, 0.3));
}

.result-crop-name {
  font-family: var(--font-display);
  font-size: 2.5rem;
  text-transform: capitalize;
  margin-bottom: 0.5rem;
}

.confidence-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  background: rgba(116, 198, 157, 0.15);
  border: 1px solid var(--accent);
  color: var(--accent);
  padding: 0.4rem 1.2rem;
  border-radius: 50px;
  font-weight: 600;
  font-size: 0.95rem;
}

.probability-bar {
  margin-bottom: 0.75rem;
}

.probability-bar .prob-label {
  display: flex;
  justify-content: space-between;
  font-size: 0.85rem;
  margin-bottom: 0.3rem;
}

.probability-bar .prob-label span:first-child {
  text-transform: capitalize;
}

.probability-bar .progress {
  height: 8px;
  background: rgba(13, 27, 18, 0.6);
  border-radius: 4px;
}

.probability-bar .progress-bar {
  background: linear-gradient(90deg, var(--primary-light), var(--accent));
  border-radius: 4px;
  transition: width 1s ease;
}

.input-summary-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(100px, 1fr));
  gap: 1rem;
}

.input-summary-item {
  text-align: center;
  padding: 1rem;
  background: rgba(13, 27, 18, 0.4);
  border-radius: var(--radius-sm);
  border: 1px solid var(--border-glass);
}

.input-summary-item .value {
  font-size: 1.25rem;
  font-weight: 600;
  color: var(--gold);
}

.input-summary-item .label {
  font-size: 0.75rem;
  color: var(--text-muted);
  text-transform: uppercase;
}

/* Compare Modal / Table */
.compare-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
}

.compare-table th,
.compare-table td {
  padding: 0.85rem 1rem;
  border-bottom: 1px solid var(--border-glass);
  text-align: center;
}

.compare-table th {
  background: rgba(26, 71, 42, 0.4);
  color: var(--accent);
  font-weight: 600;
  font-size: 0.85rem;
}

.compare-table td {
  color: var(--text-secondary);
}

.compare-table tr:hover td {
  background: rgba(116, 198, 157, 0.05);
}

.compare-winner {
  background: rgba(116, 198, 157, 0.12) !important;
  color: var(--accent) !important;
  font-weight: 600;
}

.modal-content {
  background: var(--bg-glass) !important;
  backdrop-filter: blur(16px);
  border: 1px solid var(--border-glass) !important;
  border-radius: var(--radius-lg) !important;
}

.modal-header {
  border-bottom-color: var(--border-glass) !important;
}

.modal-footer {
  border-top-color: var(--border-glass) !important;
}

.modal-title {
  font-family: var(--font-display);
}

.btn-close {
  filter: invert(1);
}

/* Flash Messages */
.flash-container {
  position: fixed;
  top: 80px;
  right: 1rem;
  z-index: 1050;
  max-width: 400px;
}

.alert {
  border-radius: var(--radius-md);
  border: 1px solid var(--border-glass);
  backdrop-filter: blur(8px);
}

.alert-success {
  background: rgba(116, 198, 157, 0.15) !important;
  color: var(--accent) !important;
  border-color: var(--accent) !important;
}

.alert-danger {
  background: rgba(231, 111, 81, 0.15) !important;
  color: var(--gold-light) !important;
  border-color: var(--gold-dark) !important;
}

.alert-warning {
  background: rgba(244, 162, 97, 0.12) !important;
  color: var(--gold) !important;
}

.alert-info {
  background: rgba(26, 71, 42, 0.4) !important;
  color: var(--text-secondary) !important;
}

/* Footer */
.opticrop-footer {
  background: rgba(13, 27, 18, 0.9);
  border-top: 1px solid var(--border-glass);
  margin-top: auto;
}

.footer-brand {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 600;
}

.footer-tagline {
  color: var(--text-muted);
  font-size: 0.85rem;
  margin: 0.25rem 0 0;
}

.footer-links a {
  color: var(--text-secondary);
  font-size: 0.9rem;
  margin: 0 0.25rem;
}

.footer-links a:hover {
  color: var(--accent);
}

/* CTA Section */
.cta-section {
  padding: 4rem 0;
}

.cta-card {
  padding: 3rem;
  text-align: center;
  background: linear-gradient(135deg, rgba(26, 71, 42, 0.5), rgba(13, 27, 18, 0.8));
  border: 1px solid var(--border-glass);
  border-radius: var(--radius-xl);
}

.cta-card h2 {
  font-size: 2rem;
  margin-bottom: 1rem;
}

.cta-card p {
  color: var(--text-secondary);
  margin-bottom: 2rem;
  max-width: 500px;
  margin-left: auto;
  margin-right: auto;
}

/* Auth Pages */
.auth-wrapper {
  min-height: calc(100vh - 200px);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem 1rem;
}

.auth-card {
  width: 100%;
  max-width: 440px;
  padding: 2.5rem;
}

.auth-logo {
  text-align: center;
  margin-bottom: 2rem;
}

.auth-logo img {
  width: 48px;
  height: 48px;
  margin-bottom: 0.75rem;
}

.auth-logo h2 {
  font-size: 1.5rem;
  margin-bottom: 0.25rem;
}

.auth-logo p {
  color: var(--text-muted);
  font-size: 0.9rem;
  margin: 0;
}

.auth-divider {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin: 1.5rem 0;
  color: var(--text-muted);
  font-size: 0.8rem;
}

.auth-divider::before,
.auth-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--border-glass);
}

/* Error Pages */
.error-page {
  min-height: 70vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 2rem;
}

.error-code {
  font-family: var(--font-display);
  font-size: 8rem;
  font-weight: 700;
  line-height: 1;
  background: linear-gradient(135deg, var(--accent), var(--gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.error-message {
  font-size: 1.25rem;
  color: var(--text-secondary);
  margin: 1rem 0 2rem;
}

/* Loading Overlay */
.loading-overlay {
  position: fixed;
  inset: 0;
  background: rgba(13, 27, 18, 0.85);
  backdrop-filter: blur(4px);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  opacity: 0;
  visibility: hidden;
  transition: opacity var(--transition), visibility var(--transition);
}

.loading-overlay.active {
  opacity: 1;
  visibility: visible;
}

.loading-spinner {
  width: 48px;
  height: 48px;
  border: 3px solid var(--border-glass);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

.loading-text {
  margin-top: 1rem;
  color: var(--text-secondary);
  font-size: 0.9rem;
}

/* Model Error Banner */
.model-error-banner {
  background: rgba(231, 111, 81, 0.12);
  border: 1px solid var(--gold-dark);
  border-radius: var(--radius-md);
  padding: 1rem 1.25rem;
  margin-bottom: 1.5rem;
  color: var(--gold-light);
  font-size: 0.9rem;
}

.model-error-banner code {
  background: rgba(0, 0, 0, 0.3);
  padding: 0.15rem 0.4rem;
  border-radius: 4px;
  color: var(--accent);
}

/* Table Overrides */
.table-dark-custom {
  --bs-table-bg: transparent;
  --bs-table-color: var(--text-secondary);
  --bs-table-border-color: var(--border-glass);
