/* OptiCrop Animations & Micro-interactions */

/* Scroll-triggered fade animations (AOS supplement) */
.fade-up {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.fade-up.visible {
  opacity: 1;
  transform: translateY(0);
}

.fade-in {
  opacity: 0;
  transition: opacity 0.6s ease;
}

.fade-in.visible {
  opacity: 1;
}

.scale-in {
  opacity: 0;
  transform: scale(0.92);
  transition: opacity 0.5s ease, transform 0.5s ease;
}

.scale-in.visible {
  opacity: 1;
  transform: scale(1);
}

.stagger-1 { transition-delay: 0.1s; }
.stagger-2 { transition-delay: 0.2s; }
.stagger-3 { transition-delay: 0.3s; }
.stagger-4 { transition-delay: 0.4s; }
.stagger-5 { transition-delay: 0.5s; }

/* Hover lift effect */
.hover-lift {
  transition: transform var(--transition), box-shadow var(--transition);
}

.hover-lift:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-glow), var(--shadow-card);
}

/* Hover glow */
.hover-glow {
  transition: box-shadow var(--transition), border-color var(--transition);
}

.hover-glow:hover {
  box-shadow: 0 0 30px rgba(116, 198, 157, 0.2);
  border-color: rgba(116, 198, 157, 0.4) !important;
}

/* Pulse accent */
.pulse-accent {
  animation: pulseAccent 2.5s ease-in-out infinite;
}

@keyframes pulseAccent {
  0%, 100% { box-shadow: 0 0 0 0 rgba(116, 198, 157, 0.3); }
  50% { box-shadow: 0 0 0 12px rgba(116, 198, 157, 0); }
}

/* Shimmer loading */
.shimmer {
  background: linear-gradient(
    90deg,
    rgba(116, 198, 157, 0.05) 25%,
    rgba(116, 198, 157, 0.15) 50%,
    rgba(116, 198, 157, 0.05) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

/* Button ripple */
.btn-ripple {
  position: relative;
  overflow: hidden;
}

.btn-ripple::after {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.25) 0%, transparent 70%);
  transform: scale(0);
  opacity: 0;
  transition: transform 0.5s ease, opacity 0.5s ease;
}

.btn-ripple:active::after {
  transform: scale(2.5);
  opacity: 1;
  transition: transform 0s, opacity 0s;
}

/* Icon bounce on hover */
.icon-bounce:hover i,
.icon-bounce:hover .feature-icon {
  animation: iconBounce 0.5s ease;
}

@keyframes iconBounce {
  0%, 100% { transform: translateY(0); }
  40% { transform: translateY(-6px); }
  60% { transform: translateY(-3px); }
}

/* Progress bar animate */
.progress-animate .progress-bar {
  animation: progressFill 1.2s ease forwards;
}

@keyframes progressFill {
  from { width: 0 !important; }
}

/* Card tilt on hover */
.card-tilt {
  transition: transform 0.4s ease;
  transform-style: preserve-3d;
}

.card-tilt:hover {
  transform: perspective(800px) rotateX(2deg) rotateY(-2deg);
}

/* Gradient border animation */
.gradient-border {
  position: relative;
  border: none !important;
}

.gradient-border::before {
  content: '';
  position: absolute;
  inset: -1px;
  border-radius: inherit;
  padding: 1px;
  background: linear-gradient(135deg, var(--accent), var(--gold), var(--primary-light));
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  opacity: 0;
  transition: opacity var(--transition);
}

.gradient-border:hover::before {
  opacity: 1;
}

/* Typing cursor */
.typing-cursor::after {
  content: '|';
  animation: blink 1s step-end infinite;
  color: var(--accent);
}

@keyframes blink {
  50% { opacity: 0; }
}

/* Slide in from sides */
.slide-left {
  opacity: 0;
  transform: translateX(-40px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

.slide-right {
  opacity: 0;
  transform: translateX(40px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

.slide-left.visible,
.slide-right.visible {
  opacity: 1;
  transform: translateX(0);
}

/* Number counter animation */
.count-up {
  display: inline-block;
}

/* Chart fade in */
.chart-fade-in {
  animation: chartFadeIn 0.8s ease forwards;
}

@keyframes chartFadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Navbar link underline */
.nav-link-animated {
  position: relative;
}

.nav-link-animated::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 2px;
  background: var(--accent);
  transition: width var(--transition), left var(--transition);
}

.nav-link-animated:hover::after,
.nav-link-animated.active::after {
  width: 60%;
  left: 20%;
}

/* Table row highlight */
.table-row-animate {
  transition: background var(--transition);
}

.table-row-animate:hover {
  background: rgba(116, 198, 157, 0.08) !important;
}

/* Modal entrance */
.modal.fade .modal-dialog {
  transform: scale(0.95) translateY(-10px);
  transition: transform 0.3s ease;
}

.modal.show .modal-dialog {
  transform: scale(1) translateY(0);
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .fade-up, .fade-in, .scale-in, .slide-left, .slide-right {
    opacity: 1;
    transform: none;
  }
}

/**
 * OptiCrop — Global JavaScript Utilities
 */
(function () {
  'use strict';

  const OptiCrop = {
    /**
     * Initialize all global behaviors on DOM ready
     */
    init() {
      this.initNavbarScroll();
      this.initFlashAutoDismiss();
      this.initScrollAnimations();
      this.initActiveNavLink();
      this.initTooltips();
    },

    /**
     * Navbar background on scroll
     */
    initNavbarScroll() {
      const nav = document.querySelector('.opticrop-nav');
      if (!nav) return;

      const onScroll = () => {
        nav.classList.toggle('scrolled', window.scrollY > 40);
      };

      window.addEventListener('scroll', onScroll, { passive: true });
      onScroll();
    },

    /**
     * Auto-dismiss flash messages after 5 seconds
     */
    initFlashAutoDismiss() {
      document.querySelectorAll('.flash-container .alert').forEach((alert) => {
        setTimeout(() => {
          const bsAlert = bootstrap.Alert.getOrCreateInstance(alert);
          bsAlert.close();
        }, 5000);
      });
    },

    /**
     * Intersection Observer for custom scroll animations
     */
    initScrollAnimations() {
      const animated = document.querySelectorAll('.fade-up, .fade-in, .scale-in, .slide-left, .slide-right');
      if (!animated.length) return;

      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add('visible');
              observer.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.15, rootMargin: '0px 0px -40px 0px' }
      );

      animated.forEach((el) => observer.observe(el));
    },

    /**
     * Highlight active nav link based on current path
     */
    initActiveNavLink() {
      const path = window.location.pathname;
      document.querySelectorAll('.navbar-nav .nav-link').forEach((link) => {
        const href = link.getAttribute('href');
        if (href === path || (href !== '/' && path.startsWith(href))) {
          link.classList.add('active');
        }
      });
    },

    /**
     * Bootstrap tooltips
     */
    initTooltips() {
      const tooltipEls = document.querySelectorAll('[data-bs-toggle="tooltip"]');
      tooltipEls.forEach((el) => new bootstrap.Tooltip(el));
    },

    /**
     * Show loading overlay
     */
    showLoading(message = 'Processing...') {
      let overlay = document.getElementById('opticrop-loading');
      if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'opticrop-loading';
        overlay.className = 'loading-overlay';
        overlay.innerHTML = `
          <div class="loading-spinner"></div>
          <p class="loading-text">${message}</p>
        `;
        document.body.appendChild(overlay);
      } else {
        overlay.querySelector('.loading-text').textContent = message;
      }
      requestAnimationFrame(() => overlay.classList.add('active'));
    },

    /**
     * Hide loading overlay
     */
    hideLoading() {
      const overlay = document.getElementById('opticrop-loading');
      if (overlay) overlay.classList.remove('active');
    },

    /**
     * Format number with commas
     */
    formatNumber(num) {
      return new Intl.NumberFormat().format(num);
    },

    /**
     * Format percentage
     */
    formatPercent(value, decimals = 1) {
      if (value == null) return 'N/A';
      return `${(value * 100).toFixed(decimals)}%`;
    },

    /**
     * Animate counting up a number
     */
    animateCounter(element, target, duration = 1500) {
      const start = 0;
      const startTime = performance.now();

      const step = (currentTime) => {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        const current = Math.round(start + (target - start) * eased);
        element.textContent = this.formatNumber(current);
        if (progress < 1) requestAnimationFrame(step);
      };

      requestAnimationFrame(step);
    },

    /**
     * Debounce utility
     */
    debounce(fn, delay = 300) {
      let timer;
      return (...args) => {
        clearTimeout(timer);
        timer = setTimeout(() => fn.apply(this, args), delay);
      };
    },

    /**
     * Fetch JSON with error handling
     */
    async fetchJSON(url, options = {}) {
      const response = await fetch(url, {
        headers: { 'Content-Type': 'application/json', ...options.headers },
        ...options,
      });

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        const message = data.error || data.errors?.join(', ') || `Request failed (${response.status})`;
        throw new Error(message);
      }

      return data;
    },

    /**
     * Capitalize first letter
     */
    capitalize(str) {
      if (!str) return '';
      return str.charAt(0).toUpperCase() + str.slice(1);
    },

    /**
     * Get crop emoji map (fallback)
     */
    cropEmojis: {
      rice: '🌾', maize: '🌽', chickpea: '🌰', kidneybeans: '🫘',
      pigeonpeas: '🟤', mothbeans: '🟡', mungbean: '🟢', blackgram: '⚫',
      lentil: '🫘', pomegranate: '🍑', banana: '🍌', mango: '🥭',
      grapes: '🍇', watermelon: '🍉', muskmelon: '🍈', apple: '🍎',
      orange: '🍊', papaya: '🍐', coconut: '🥥', cotton: '🌸',
      jute: '🌿', coffee: '☕',
    },

    getCropEmoji(crop) {
      return this.cropEmojis[crop?.toLowerCase()] || '🌿';
    },
  };

  window.OptiCrop = OptiCrop;

  document.addEventListener('DOMContentLoaded', () => OptiCrop.init());
})();

/**
 * OptiCrop — Prediction Form AJAX & Interactions
 */
(function () {
  'use strict';

  const SAMPLE_PRESETS = {
    rice: { nitrogen: 90, phosphorous: 42, potassium: 43, temperature: 25, humidity: 80, ph: 6.5, rainfall: 200 },
    maize: { nitrogen: 85, phosphorous: 58, potassium: 41, temperature: 28, humidity: 65, ph: 7.0, rainfall: 120 },
    cotton: { nitrogen: 120, phosphorous: 45, potassium: 35, temperature: 32, humidity: 55, ph: 7.2, rainfall: 80 },
    coffee: { nitrogen: 100, phosphorous: 35, potassium: 40, temperature: 22, humidity: 75, ph: 6.0, rainfall: 150 },
    apple: { nitrogen: 20, phosphorous: 130, potassium: 280, temperature: 15, humidity: 60, ph: 6.5, rainfall: 100 },
  };

  const FIELD_MAP = {
    nitrogen: 'nitrogen',
    phosphorous: 'phosphorous',
    potassium: 'potassium',
    temperature: 'temperature',
    humidity: 'humidity',
    ph: 'ph',
    rainfall: 'rainfall',
  };

  function getFormValues(form) {
    const values = {};
    Object.keys(FIELD_MAP).forEach((key) => {
      const input = form.querySelector(`[name="${key}"]`);
      values[key] = input ? parseFloat(input.value) : null;
    });
    return values;
  }

  function setFormValues(form, values) {
    Object.entries(values).forEach(([key, val]) => {
      const input = form.querySelector(`[name="${key}"]`);
      if (input) input.value = val;
    });
  }

  function initSamplePresets() {
    document.querySelectorAll('.sample-btn').forEach((btn) => {
      btn.addEventListener('click', () => {
        const preset = btn.dataset.preset;
        const form = document.getElementById('predict-form');
        if (form && SAMPLE_PRESETS[preset]) {
          setFormValues(form, SAMPLE_PRESETS[preset]);
          document.querySelectorAll('.sample-btn').forEach((b) => b.classList.remove('active'));
          btn.classList.add('active');
        }
      });
    });
  }

  function initAjaxPredict() {
    const form = document.getElementById('predict-form');
    const ajaxBtn = document.getElementById('ajax-predict-btn');
    if (!form || !ajaxBtn) return;

    ajaxBtn.addEventListener('click', async (e) => {
      e.preventDefault();

      const algorithm = form.querySelector('input[name="algorithm"]:checked')?.value || 'random_forest';
      const values = getFormValues(form);

      OptiCrop.showLoading('Analyzing soil & climate data...');

      try {
        const result = await OptiCrop.fetchJSON(`/predict/${algorithm}`, {
          method: 'POST',
          body: JSON.stringify(values),
        });

        showAjaxResult(result);
      } catch (err) {
        showAjaxError(err.message);
      } finally {
        OptiCrop.hideLoading();
      }
    });
  }

  function showAjaxResult(result) {
    const container = document.getElementById('ajax-result-preview');
    if (!container) return;

    if (result.error) {
      container.innerHTML = `<div class="model-error-banner">${result.error}</div>`;
      container.classList.remove('d-none');
      return;
    }

    const confidence = result.confidence
      ? `<span class="confidence-badge"><i class="fas fa-chart-line"></i> ${OptiCrop.formatPercent(result.confidence)}</span>`
      : '';

    let probBars = '';
    if (result.probabilities) {
      probBars = Object.entries(result.probabilities)
        .map(([crop, prob]) => `
          <div class="probability-bar">
            <div class="prob-label">
              <span>${OptiCrop.getCropEmoji(crop)} ${OptiCrop.capitalize(crop)}</span>
              <span>${OptiCrop.formatPercent(prob)}</span>
            </div>
            <div class="progress">
              <div class="progress-bar" style="width: ${prob * 100}%"></div>
            </div>
          </div>
        `)
        .join('');
    }

    container.innerHTML = `
      <div class="glass-card p-4 mt-3" data-aos="fade-up">
        <div class="text-center mb-3">
          <div class="result-crop-emoji">${result.emoji || OptiCrop.getCropEmoji(result.crop)}</div>
          <h3 class="result-crop-name">${OptiCrop.capitalize(result.crop)}</h3>
          ${confidence}
        </div>
        ${probBars ? `<div class="mt-3">${probBars}</div>` : ''}
        <p class="text-muted-custom text-center mt-3 mb-0 small">${result.description || ''}</p>
      </div>
    `;
    container.classList.remove('d-none');
  }

  function showAjaxError(message) {
    const container = document.getElementById('ajax-result-preview');
    if (container) {
      container.innerHTML = `<div class="alert alert-danger mt-3">${message}</div>`;
      container.classList.remove('d-none');
    }
  }

  function initCompareModal() {
    const compareBtn = document.getElementById('compare-modal-btn');
    const compareModal = document.getElementById('compareModal');
    if (!compareBtn || !compareModal) return;

    compareBtn.addEventListener('click', async () => {
      const form = document.getElementById('predict-form');
      if (!form) return;

      const values = getFormValues(form);
      const modalBody = compareModal.querySelector('.compare-results-body');
      modalBody.innerHTML = '<div class="text-center py-4"><div class="loading-spinner mx-auto"></div><p class="loading-text mt-2">Comparing all algorithms...</p></div>';

      const modal = bootstrap.Modal.getOrCreateInstance(compareModal);
      modal.show();

      try {
        const results = await OptiCrop.fetchJSON('/compare', {
          method: 'POST',
          body: JSON.stringify({
            nitrogen: values.nitrogen,
            phosphorous: values.phosphorous,
            potassium: values.potassium,
            temperature: values.temperature,
            humidity: values.humidity,
            ph: values.ph,
            rainfall: values.rainfall,
          }),
        });

        renderCompareTable(modalBody, results);
      } catch (err) {
        modalBody.innerHTML = `<div class="alert alert-danger">${err.message}</div>`;
      }
    });
  }

  function renderCompareTable(container, results) {
    const algos = Object.keys(results);
    let maxConf = -1;
    let winner = null;

    algos.forEach((algo) => {
      const conf = results[algo].confidence;
      if (conf != null && conf > maxConf) {
        maxConf = conf;
        winner = algo;
      }
    });

    const rows = algos
      .map((algo) => {
        const r = results[algo];
        const isWinner = algo === winner;
        const conf = r.confidence != null ? OptiCrop.formatPercent(r.confidence) : 'N/A';
        return `
          <tr class="${isWinner ? 'compare-winner' : ''}">
            <td>${algo.replace('_', ' ')}</td>
            <td>${r.emoji || OptiCrop.getCropEmoji(r.crop)} ${OptiCrop.capitalize(r.crop)}</td>
            <td>${conf}</td>
            <td>${r.season || '—'}</td>
            <td>${r.water || '—'}</td>
          </tr>
        `;
      })
      .join('');

    container.innerHTML = `
      <div class="table-responsive">
        <table class="compare-table">
          <thead>
            <tr>
              <th>Algorithm</th>
              <th>Predicted Crop</th>
              <th>Confidence</th>
              <th>Season</th>
              <th>Water Need</th>
            </tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    `;
  }

  function initFormValidation() {
    const form = document.getElementById('predict-form');
    if (!form) return;

    form.addEventListener('submit', () => {
      OptiCrop.showLoading('Running prediction...');
    });
  }

  document.addEventListener('DOMContentLoaded', () => {
    initSamplePresets();
    initAjaxPredict();
    initCompareModal();
    initFormValidation();
  });
})();

/**
 * OptiCrop — Chart.js Visualization Helpers
 */
(function () {
  'use strict';

  const CHART_COLORS = {
    primary: '#1a472a',
    accent: '#74c69d',
    accentLight: '#95d5b2',
    gold: '#f4a261',
    goldDark: '#e76f51',
    palette: ['#74c69d', '#40916c', '#f4a261', '#e76f51', '#2d6a4f', '#95d5b2', '#52b788', '#b7e4c7'],
  };

  const defaultOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        labels: {
          color: '#a8c5b0',
          font: { family: 'Inter, sans-serif', size: 11 },
          padding: 16,
        },
      },
      tooltip: {
        backgroundColor: 'rgba(13, 27, 18, 0.92)',
        titleColor: '#e8f5e9',
        bodyColor: '#a8c5b0',
        borderColor: 'rgba(116, 198, 157, 0.3)',
        borderWidth: 1,
        cornerRadius: 8,
        padding: 12,
      },
    },
  };

  const OptiCropCharts = {
    instances: {},

    /**
     * Shared scale config for dark theme
     */
    darkScales() {
      const axisStyle = {
        ticks: { color: '#6b8f7a', font: { size: 10 } },
        grid: { color: 'rgba(116, 198, 157, 0.08)' },
      };
      return {
        x: { ...axisStyle },
        y: { ...axisStyle, beginAtZero: true },
      };
    },

    /**
     * Model accuracy bar chart
     */
    createAccuracyChart(canvasId, accuracies) {
      const ctx = document.getElementById(canvasId);
      if (!ctx) return null;

      const labels = Object.keys(accuracies);
      const data = Object.values(accuracies).map((v) => (v * 100).toFixed(1));

      return this._create(canvasId, {
        type: 'bar',
        data: {
          labels,
          datasets: [{
            label: 'Accuracy (%)',
            data,
            backgroundColor: CHART_COLORS.palette.map((c) => c + 'cc'),
            borderColor: CHART_COLORS.palette,
            borderWidth: 1,
            borderRadius: 6,
          }],
        },
        options: {
          ...defaultOptions,
          scales: {
            ...this.darkScales(),
            y: { ...this.darkScales().y, max: 100 },
          },
          plugins: {
            ...defaultOptions.plugins,
            legend: { display: false },
          },
        },
      });
    },

    /**
     * Feature importance horizontal bar
     */
    createFeatureImportanceChart(canvasId, importance) {
      const ctx = document.getElementById(canvasId);
      if (!ctx) return null;

      const sorted = Object.entries(importance).sort((a, b) => b[1] - a[1]);
      const labels = sorted.map(([k]) => k);
      const data = sorted.map(([, v]) => (v * 100).toFixed(1));

      return this._create(canvasId, {
        type: 'bar',
        data: {
          labels,
          datasets: [{
            label: 'Importance (%)',
            data,
            backgroundColor: CHART_COLORS.accent + 'aa',
            borderColor: CHART_COLORS.accent,
            borderWidth: 1,
            borderRadius: 4,
          }],
        },
        options: {
          indexAxis: 'y',
          ...defaultOptions,
          scales: this.darkScales(),
          plugins: { ...defaultOptions.plugins, legend: { display: false } },
        },
      });
    },

    /**
     * Crop distribution doughnut
     */
    createCropDistributionChart(canvasId, distribution) {
      const ctx = document.getElementById(canvasId);
      if (!ctx) return null;

      const labels = Object.keys(distribution);
      const data = Object.values(distribution);

      return this._create(canvasId, {
        type: 'doughnut',
        data: {
          labels: labels.map((l) => l.charAt(0).toUpperCase() + l.slice(1)),
          datasets: [{
            data,
            backgroundColor: CHART_COLORS.palette,
            borderColor: '#0d1b12',
            borderWidth: 2,
          }],
        },
        options: {
          ...defaultOptions,
          cutout: '60%',
        },
      });
    },

    /**
     * Prediction timeline line chart
     */
    createTimelineChart(canvasId, timeline) {
      const ctx = document.getElementById(canvasId);
      if (!ctx) return null;

      const labels = Object.keys(timeline);
      const data = Object.values(timeline);

      return this._create(canvasId, {
        type: 'line',
        data: {
          labels: labels.map((d) => d.slice(5)),
          datasets: [{
            label: 'Predictions',
            data,
            borderColor: CHART_COLORS.accent,
            backgroundColor: CHART_COLORS.accent + '33',
            fill: true,
            tension: 0.4,
            pointBackgroundColor: CHART_COLORS.gold,
            pointRadius: 3,
            pointHoverRadius: 6,
          }],
        },
        options: {
          ...defaultOptions,
          scales: this.darkScales(),
          plugins: { ...defaultOptions.plugins, legend: { display: false } },
        },
      });
    },

    /**
     * Algorithm usage pie chart
     */
    createAlgorithmUsageChart(canvasId, usage) {
      const ctx = document.getElementById(canvasId);
      if (!ctx) return null;

      const labels = Object.keys(usage).map((a) => a.replace('_', ' '));
      const data = Object.values(usage);

      return this._create(canvasId, {
        type: 'pie',
        data: {
          labels,
          datasets: [{
            data,
            backgroundColor: CHART_COLORS.palette,
            borderColor: '#0d1b12',
            borderWidth: 2,
          }],
        },
        options: defaultOptions,
      });
    },

    /**
     * Confusion matrix heatmap-style bar
     */
    createConfusionMatrixChart(canvasId, confusionData) {
      const ctx = document.getElementById(canvasId);
      if (!ctx || !confusionData) return null;

      const labels = confusionData.labels || [];
      const matrix = confusionData.matrix || [];

      const datasets = labels.map((label, i) => ({
        label: label.charAt(0).toUpperCase() + label.slice(1),
        data: matrix[i] || [],
        backgroundColor: CHART_COLORS.palette[i % CHART_COLORS.palette.length] + 'cc',
        borderRadius: 2,
      }));

      return this._create(canvasId, {
        type: 'bar',
        data: { labels, datasets },
        options: {
          ...defaultOptions,
          scales: {
            x: { stacked: true, ...this.darkScales().x },
            y: { stacked: true, ...this.darkScales().y, max: 100 },
          },
        },
      });
    },

    /**
     * Destroy all chart instances
     */
    destroyAll() {
      Object.values(this.instances).forEach((chart) => chart.destroy());
      this.instances = {};
    },

    _create(id, config) {
      if (this.instances[id]) {
        this.instances[id].destroy();
      }
      const chart = new Chart(document.getElementById(id), config);
      this.instances[id] = chart;
      return chart;
    },
  };

  window.OptiCropCharts = OptiCropCharts;
})();

/**
 * OptiCrop — Dashboard Interactivity
 */
(function () {
  'use strict';

  function initCounterAnimations() {
    document.querySelectorAll('[data-count]').forEach((el) => {
      const target = parseInt(el.dataset.count, 10);
      if (!isNaN(target)) {
        OptiCrop.animateCounter(el, target);
      }
    });
  }

  function initHistoryFilters() {
    const table = document.getElementById('history-table');
    if (!table) return;

    const cropFilter = document.getElementById('filter-crop');
    const algoFilter = document.getElementById('filter-algorithm');
    const searchInput = document.getElementById('filter-search');
    const rows = table.querySelectorAll('tbody tr');

    function applyFilters() {
      const cropVal = cropFilter?.value?.toLowerCase() || '';
      const algoVal = algoFilter?.value?.toLowerCase() || '';
      const searchVal = searchInput?.value?.toLowerCase() || '';

      let visibleCount = 0;

      rows.forEach((row) => {
        const crop = row.dataset.crop?.toLowerCase() || '';
        const algo = row.dataset.algorithm?.toLowerCase() || '';
        const text = row.textContent.toLowerCase();

        const matchCrop = !cropVal || crop === cropVal;
        const matchAlgo = !algoVal || algo === algoVal;
        const matchSearch = !searchVal || text.includes(searchVal);

        const visible = matchCrop && matchAlgo && matchSearch;
        row.style.display = visible ? '' : 'none';
        if (visible) visibleCount++;
      });

      const emptyState = document.getElementById('history-empty-filter');
      if (emptyState) {
        emptyState.classList.toggle('d-none', visibleCount > 0);
      }
    }

    cropFilter?.addEventListener('change', applyFilters);
    algoFilter?.addEventListener('change', applyFilters);
    searchInput?.addEventListener('input', OptiCrop.debounce(applyFilters, 250));
  }

  async function initAnalyticsCharts() {
    const analyticsPage = document.getElementById('analytics-page');
    if (!analyticsPage) return;

    const loadingEl = document.getElementById('analytics-loading');
    const chartsEl = document.getElementById('analytics-charts');

    try {
      const stats = await OptiCrop.fetchJSON('/api/v1/stats');

      if (loadingEl) loadingEl.classList.add('d-none');
      if (chartsEl) chartsEl.classList.remove('d-none');

      updateMiniStats(stats);

      OptiCropCharts.createAccuracyChart('chart-accuracy', stats.model_accuracies || {});
      OptiCropCharts.createFeatureImportanceChart('chart-features', stats.feature_importance || {});
      OptiCropCharts.createCropDistributionChart('chart-crops', stats.crop_distribution || {});
      OptiCropCharts.createTimelineChart('chart-timeline', stats.prediction_timeline || {});
      OptiCropCharts.createAlgorithmUsageChart('chart-algorithms', stats.algorithm_usage || {});

      if (stats.confusion_matrix) {
        OptiCropCharts.createConfusionMatrixChart('chart-confusion', stats.confusion_matrix);
      }
    } catch (err) {
      if (loadingEl) {
        loadingEl.innerHTML = `<div class="alert alert-danger">${err.message}</div>`;
      }
    }
  }

  function updateMiniStats(stats) {
    const totalEl = document.getElementById('stat-total-predictions');
    const cropCountEl = document.getElementById('stat-unique-crops');
    const algoCountEl = document.getElementById('stat-algorithms-used');
    const bestModelEl = document.getElementById('stat-best-model');

    if (totalEl && stats.total_predictions != null) {
      OptiCrop.animateCounter(totalEl, stats.total_predictions);
    }

    if (cropCountEl && stats.crop_distribution) {
      OptiCrop.animateCounter(cropCountEl, Object.keys(stats.crop_distribution).length);
    }

    if (algoCountEl && stats.algorithm_usage) {
      OptiCrop.animateCounter(algoCountEl, Object.keys(stats.algorithm_usage).length);
    }

    if (bestModelEl && stats.model_accuracies) {
      const best = Object.entries(stats.model_accuracies).reduce(
        (max, [name, acc]) => (acc > max.acc ? { name, acc } : max),
        { name: '—', acc: 0 }
      );
      bestModelEl.textContent = best.name;
    }
  }

  function initComparePage() {
    const form = document.getElementById('compare-form');
    if (!form) return;

    form.addEventListener('submit', async (e) => {
      e.preventDefault();
      OptiCrop.showLoading('Running all algorithms...');

      const formData = new FormData(form);
      const payload = {};
      formData.forEach((val, key) => { payload[key] = parseFloat(val); });

      try {
        const results = await OptiCrop.fetchJSON('/compare', {
          method: 'POST',
          body: JSON.stringify(payload),
        });
        renderComparePageResults(results);
      } catch (err) {
        document.getElementById('compare-results').innerHTML =
          `<div class="alert alert-danger">${err.message}</div>`;
      } finally {
        OptiCrop.hideLoading();
      }
    });
  }

  function renderComparePageResults(results) {
    const container = document.getElementById('compare-results');
    if (!container) return;

    const cards = Object.entries(results)
      .map(([algo, r]) => {
        const conf = r.confidence != null
          ? `<span class="confidence-badge">${OptiCrop.formatPercent(r.confidence)}</span>`
          : '<span class="text-muted-custom">N/A</span>';

        return `
          <div class="col-md-6 col-lg-4" data-aos="fade-up">
            <div class="glass-card p-4 h-100 hover-lift">
              <div class="d-flex justify-content-between align-items-start mb-3">
                <span class="algo-badge">${algo.replace('_', ' ')}</span>
                ${conf}
              </div>
              <div class="text-center">
                <div class="result-crop-emoji" style="font-size:3rem">${r.emoji || OptiCrop.getCropEmoji(r.crop)}</div>
                <h4 class="result-crop-name" style="font-size:1.5rem">${OptiCrop.capitalize(r.crop)}</h4>
              </div>
              <p class="text-muted-custom small mt-2 mb-0">${r.description || ''}</p>
              <div class="d-flex gap-3 mt-3 small text-muted-custom">
                <span><i class="fas fa-calendar"></i> ${r.season || '—'}</span>
                <span><i class="fas fa-tint"></i> ${r.water || '—'}</span>
              </div>
            </div>
          </div>
        `;
      })
      .join('');

    container.innerHTML = `<div class="row g-4">${cards}</div>`;
    AOS.refresh();
  }

  document.addEventListener('DOMContentLoaded', () => {
    initCounterAnimations();
    initHistoryFilters();
    initAnalyticsCharts();
    initComparePage();
  });
})();
